import{_ as e,c as t,a2 as p,o as r}from"./chunks/framework.DPuwY6B9.js";const o="/payment/alipay/1.png",l="/payment/alipay/2.png",i="/payment/alipay/3.png",n="/payment/alipay/4.png",h="/payment/alipay/5.png",c="/payment/alipay/6.png",s="/payment/alipay/7.png",m="/payment/alipay/8.png",d="/payment/alipay/10.png",b="/payment/alipay/11.png",y="/payment/paypal/1.png",u="/payment/paypal/2.png",_="/payment/paypal/3.png",g="/payment/paypal/4.png",D=JSON.parse('{"title":"支付驱动","description":"","frontmatter":{},"headers":[],"relativePath":"guide/payment.md","filePath":"zh/guide/payment.md","lastUpdated":1732511693000}'),k={name:"guide/payment.md"};function f(q,a,P,x,v,W){return r(),t("div",null,a[0]||(a[0]=[p('<h1 id="支付驱动" tabindex="-1">支付驱动 <a class="header-anchor" href="#支付驱动" aria-label="Permalink to &quot;支付驱动&quot;">​</a></h1><p>兰空图床当前仅支持官方<a href="https://open.alipay.com/api/detail?code=I1080300001000041203&amp;index=0" target="_blank" rel="noreferrer">支付宝电脑网站支付</a>、<a href="https://pay.wechatpay.cn/wiki/doc/apiv3_partner/open/pay/chapter2_7_0.shtml" target="_blank" rel="noreferrer">微信 Native 支付</a>，<a href="https://paypal.com" target="_blank" rel="noreferrer">PayPal</a>，并且支付宝仅支持证书模式、微信仅支持 V3 版本。</p><div class="warning custom-block"><p class="custom-block-title">为什么不适配易支付等支付接口聚合平台？</p><ul><li>易支付属于无支付资质、非官方认证的机构。</li><li>资金由易支付托管，可能会涉及到非法集资、资金截留等问题。</li><li>若管理不当，会有泄露风险(用户信息、交易记录等)。</li></ul></div><h2 id="支付宝" tabindex="-1">支付宝 <a class="header-anchor" href="#支付宝" aria-label="Permalink to &quot;支付宝&quot;">​</a></h2><h3 id="创建支付应用" tabindex="-1">创建支付应用 <a class="header-anchor" href="#创建支付应用" aria-label="Permalink to &quot;创建支付应用&quot;">​</a></h3><p>前往开发者中心，点击 <a href="https://open.alipay.com/develop/pm/create" target="_blank" rel="noreferrer">https://open.alipay.com/develop/pm/create</a> 创建网页移动应用。</p><p><img src="'+o+'" alt="创建应用"></p><h3 id="绑定支付宝支付产品" tabindex="-1">绑定支付宝支付产品 <a class="header-anchor" href="#绑定支付宝支付产品" aria-label="Permalink to &quot;绑定支付宝支付产品&quot;">​</a></h3><p>创建好应用后进入应用，点击「产品绑定」，选择「支付」-&gt; 「电脑网站支付」</p><p><img src="'+l+'" alt="绑定支付"></p><h3 id="开通电脑网站支付" tabindex="-1">开通电脑网站支付 <a class="header-anchor" href="#开通电脑网站支付" aria-label="Permalink to &quot;开通电脑网站支付&quot;">​</a></h3><p>绑定完成后，如果显示「产品开通状态」显示为「未开通」则需要根据支付宝的指引去开通，否则支付功能无法使用。</p><p><img src="'+i+'" alt="开通支付"></p><h3 id="设置加签方式" tabindex="-1">设置加签方式 <a class="header-anchor" href="#设置加签方式" aria-label="Permalink to &quot;设置加签方式&quot;">​</a></h3><p><img src="'+n+'" alt="设置加签方式"><img src="'+h+'" alt="选择加签方式"></p><p>加签方式选择第二项「证书」</p><h3 id="下载证书生成软件" tabindex="-1">下载证书生成软件 <a class="header-anchor" href="#下载证书生成软件" aria-label="Permalink to &quot;下载证书生成软件&quot;">​</a></h3><p><img src="'+c+'" alt="下载证书生成工具"></p><h3 id="生成证书并上传" tabindex="-1">生成证书并上传 <a class="header-anchor" href="#生成证书并上传" aria-label="Permalink to &quot;生成证书并上传&quot;">​</a></h3><p><img src="'+s+'" alt="生成证书并上传"></p><h3 id="下载证书" tabindex="-1">下载证书 <a class="header-anchor" href="#下载证书" aria-label="Permalink to &quot;下载证书&quot;">​</a></h3><p>上传成功后，将证书全部下载。</p><p><img src="'+m+'" alt="下载证书"></p><h3 id="设置回调地址" tabindex="-1">设置回调地址 <a class="header-anchor" href="#设置回调地址" aria-label="Permalink to &quot;设置回调地址&quot;">​</a></h3><p>回调地址固定为 站点域名 + <code>payment/callback</code>，假设站点域名为 <code>http://example.com</code>，即：<code>http://example.com/payment/callback</code> 将其填入支付宝的授权回调地址中。</p><p><img src="'+d+'" alt="填写授权回调地址"></p><h3 id="上传证书" tabindex="-1">上传证书 <a class="header-anchor" href="#上传证书" aria-label="Permalink to &quot;上传证书&quot;">​</a></h3><p>然后打开刚刚由证书生成软件生成的证书目录，复制 <code>应用私钥RSA2048-敏感数据，请妥善保管.txt</code> 文件内容，将其填写到兰空图床后台配置中，并上传三份证书文件。</p><p><img src="'+b+'" alt="上传证书"></p><p>上传完成后点击保存即可。</p><h2 id="微信" tabindex="-1">微信 <a class="header-anchor" href="#微信" aria-label="Permalink to &quot;微信&quot;">​</a></h2><p>todo</p><h2 id="paypal" tabindex="-1">PayPal <a class="header-anchor" href="#paypal" aria-label="Permalink to &quot;PayPal&quot;">​</a></h2><h3 id="创建应用" tabindex="-1">创建应用 <a class="header-anchor" href="#创建应用" aria-label="Permalink to &quot;创建应用&quot;">​</a></h3><p>进入开发者中心，点击 Create App 来创建一个应用，注意，文档图片中处于沙盒环境。</p><p><img src="'+y+'" alt="创建应用"></p><p>Type 选择 Merchant</p><p><img src="'+u+'" alt="创建应用"></p><p>点击 Create App 确认创建。</p><h3 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h3><p><img src="'+_+'" alt="配置"></p><h3 id="webhook" tabindex="-1">Webhook <a class="header-anchor" href="#webhook" aria-label="Permalink to &quot;Webhook&quot;">​</a></h3><p>同样的，PayPal 我们也需要配置回调，即 Webhook。我们点击进应用详情，滚动到最底部，找到 Webhook 那一栏，创建一个 Webhook。</p><p><img src="'+g+'" alt="Webhook"></p><p>创建成功后我们会在列表看到 Webhook ID。</p><p>将应用的 Client ID 和 Secret key 以及 WebHook ID 填入兰空图片后台支付配置中既可。</p>',46)]))}const I=e(k,[["render",f]]);export{D as __pageData,I as default};
